args.sparql:
SELECT ?gameLabel ?protagonistLabel ?ethnicityLabel WHERE {
  ?game wdt:P179 wd:Q15252 ;
        wdt:P31 wd:Q7889 ;
        wdt:P1552 ?protagonist.
  ?protagonist wdt:P103 ?ethnicity.
  ?game rdfs:label ?gameLabel .
  ?protagonist rdfs:label ?protagonistLabel .
  ?ethnicity rdfs:label ?ethnicityLabel .
  FILTER (LANG(?gameLabel) = 'en')
  FILTER (LANG(?protagonistLabel) = 'en')
  FILTER (LANG(?ethnicityLabel) = 'en')
}
